def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 10
        oscillation = 0.0
        penalty = 0.0
        bonus = 0.0
        for step in range(steps):
            if ratio > 1.2:
                score += 80 * decay
                penalty += 15 * decay
                break
            if ratio < 0.001:
                score += 0.05 * decay
                bonus += 5 * decay
                break
            exp_comp = np.exp(-ratio * (step + 1) * 1.5)
            tanh_comp = np.tanh(ratio * 15 * (step + 1))
            log_comp = np.log1p(ratio * 120) / (step + 2)
            sin_comp = np.sin(ratio * np.pi * (step + 0.3))
            cos_comp = np.cos(ratio * np.pi * (step + 0.7))
            oscillation += (sin_comp**2 + cos_comp**2) * decay
            score += (exp_comp + tanh_comp + log_comp) * decay + oscillation * 0.2
            if 0.1 < ratio < 0.4:
                score += (5 - step) * 0.4 * decay
                bonus += 1.2 * step * decay
            elif 0.5 < ratio < 0.75:
                score -= step * 0.7 * decay
                penalty += 2 * decay
            elif 0.8 < ratio < 1.0:
                score += 0.3 * step * decay
                bonus += 0.5 * decay
            else:
                score += 0.1 * step * decay
            decay *= 0.65
            if score > 20:
                break
        if ratio < 0.6:
            for k in range(5):
                sq_term = ((0.6 / (k + 1)) * (1 - ratio)) ** 2
                score += sq_term * decay
                if k % 2 == 0:
                    penalty += sq_term * 0.5 * decay
                else:
                    bonus += sq_term * 0.3 * decay
        elif ratio > 0.8:
            for k in range(4):
                threshold = item * (1 + 0.05 * k)
                if capacity < threshold:
                    score += 4 * (k + 1) * decay
                    penalty += (k + 1) * 1.5 * decay
                else:
                    bonus += (k + 1) * 0.8 * decay
        if capacity < item * 0.9:
            score += 30
            penalty += 10
        elif capacity > item * 1.8:
            score /= 2
            bonus += 5
        score += bonus - penalty
        extra_factor = np.sum(np.array([np.sin(item * (j + 1)) for j in range(3)])) * 0.1
        if extra_factor > 0:
            score *= (1 - extra_factor)
        else:
            score *= (1 + abs(extra_factor))
        if np.isclose(ratio, 0.5, atol=0.05):
            score *= 0.85
        if score < 0:
            score = 0
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 300
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 2.0
            else:
                priorities[i] = (priorities[i] - p_min) / (p_max - p_min) * 25
    return priorities
